44	async function getUserInfo(token) {
45	  return new Promise((resolve) => {
46	    jwt.verify(token, publicKey, verifyOptions, (err, decoded) => {
47	    if (err) {
48	        resolve(null);
49	    } else {
50	        resolve(decoded);
51	    }
52	    });
53	  });
54	};
